python3 -c "
import json, re

with open('/workspace/chords.json') as f:
    segs = json.load(f)

pattern = re.compile(r'^[A-G]#?:(maj|min)$')
allowed = set([
    'C:maj','C#:maj','D:maj','D#:maj','E:maj','F:maj','F#:maj','G:maj','G#:maj','A:maj','A#:maj','B:maj',
    'C:min','C#:min','D:min','D#:min','E:min','F:min','F#:min','G:min','G#:min','A:min','A#:min','B:min'
])

print(f'Total segments : {len(segs)}')
print(f'First          : {segs[0]}')
print(f'Last           : {segs[-1]}')

errors = []
for i, s in enumerate(segs):
    if not isinstance(s[\"start\"], (int, float)): errors.append(f'[{i}] start not number')
    if not isinstance(s[\"end\"],   (int, float)): errors.append(f'[{i}] end not number')
    if s[\"start\"] >= s[\"end\"]:                   errors.append(f'[{i}] start >= end')
    if not pattern.match(s[\"chord\"]):             errors.append(f'[{i}] bad chord: {s[\"chord\"]}')
    if s[\"chord\"] not in allowed:                 errors.append(f'[{i}] chord not in allowed set')
    if i > 0 and segs[i-1][\"end\"] != s[\"start\"]: errors.append(f'[{i}] gap/overlap with previous')

unique = set(s[\"chord\"] for s in segs)
print(f'Unique chords  : {len(unique)} -> {sorted(unique)}')
print(f'Coverage       : {segs[0][\"start\"]}s to {segs[-1][\"end\"]}s')
print(f'Errors         : {errors if errors else \"None — all checks passed ✓\"}')
"

